(() => {
  const TARGETS = __EV4_TARGETS_JSON__;
  const TEMPLATE_ID = 'elementor_rendered_dom_computed_v1';
  const TEMPLATE_VERSION = '1.0.0';
  const LIMITATION = 'This reads rendered DOM/computed CSS only. It does not prove hidden Elementor panel values unless reflected in DOM/CSS or shown in a screenshot.';
  const computedNames = ['display','position','width','height','min-width','min-height','max-width','max-height','padding-top','padding-right','padding-bottom','padding-left','margin-top','margin-right','margin-bottom','margin-left','gap','row-gap','column-gap','transform','z-index','overflow','overflow-x','overflow-y','flex-direction','align-items','justify-content','grid-template-columns','grid-template-rows'];
  function executionContext() {
    const topWindow = window.parent === window;
    const hasFrontend = typeof window.elementorFrontend !== 'undefined';
    const bodyClass = document.body ? String(document.body.className || '') : '';
    const htmlClass = document.documentElement ? String(document.documentElement.className || '') : '';
    const looksEditor = bodyClass.includes('elementor-editor') || htmlClass.includes('elementor-editor') || location.href.includes('elementor');
    if (!topWindow && hasFrontend) return 'editor_iframe';
    if (!topWindow) return 'editor_iframe';
    if (topWindow && looksEditor && !hasFrontend) return 'editor_parent_shell';
    if (hasFrontend) return 'frontend';
    return 'unknown';
  }
  function attrs(el) {
    const out = {};
    for (const name of ['id','class','data-id','data-element_type','data-widget_type']) {
      if (el.hasAttribute && el.hasAttribute(name)) out[name] = el.getAttribute(name);
    }
    return out;
  }
  function boxOf(el) {
    const b = el.getBoundingClientRect();
    return { x: b.x, y: b.y, width: b.width, height: b.height, top: b.top, right: b.right, bottom: b.bottom, left: b.left };
  }
  function computedOf(el) {
    const cs = getComputedStyle(el);
    const out = {};
    for (const name of computedNames) out[name] = cs.getPropertyValue(name) || null;
    return out;
  }
  const output = {
    diagnosticType: 'read-only rendered DOM/computed-style evidence',
    templateId: TEMPLATE_ID,
    templateVersion: TEMPLATE_VERSION,
    timestamp: new Date().toISOString(),
    url: String(location.href),
    executionContext: executionContext(),
    viewport: { width: window.innerWidth, height: window.innerHeight, devicePixelRatio: window.devicePixelRatio || 1 },
    limitation: LIMITATION,
    targets: TARGETS.map((target) => {
      const nodes = Array.from(document.querySelectorAll(target.selector));
      const sampled = nodes.slice(0, 10).map((el, index) => ({
        index,
        tag: el.tagName ? el.tagName.toLowerCase() : '',
        id: el.id || null,
        classes: Array.from(el.classList || []),
        attributes: attrs(el),
        box: boxOf(el),
        computed: computedOf(el)
      }));
      return { label: target.label, selector: target.selector, matchCount: nodes.length, matches: sampled, truncated: nodes.length > sampled.length };
    })
  };
  console.log(JSON.stringify(output, null, 2));
  return output;
})()
